import{_ as t,o as r,c as n,ag as s}from"./chunks/framework.BZohXCq9.js";const l=JSON.parse('{"title":"术语表","description":"","frontmatter":{},"headers":[],"relativePath":"creator-guide/12-glossary.md","filePath":"creator-guide/12-glossary.md","lastUpdated":null}'),e={name:"creator-guide/12-glossary.md"};function p(g,o,a,d,i,c){return r(),n("div",null,[...o[0]||(o[0]=[s('<div><h1 id="术语表" tabindex="-1">术语表 <a class="header-anchor" href="#术语表" aria-label="Permalink to &quot;术语表&quot;">​</a></h1><p>按拼音/首字母排序的 Yumina 创作术语速查。</p><hr><p><strong>背包格子（Inventory Grid）</strong> — 一种组件类型，绑定 JSON 数组变量后以网格形式展示物品列表，玩家获得或失去物品时格子自动更新。</p><p><strong>变量（Variable）</strong> — 存储游戏状态数据的命名容器，支持数字、文字、布尔和 JSON 四种类型，是指令和规则读写的核心对象。</p><p><strong>播放列表（Playlist）</strong> — BGM 播放列表配置，可将多首背景音乐按顺序、循环或随机模式串联播放，并控制是否自动播放和曲间间隔。</p><p><strong>词条（Entry）</strong> — 世界中的一个内容片段，包含文本和触发条件，是构建角色设定、世界观、剧情线索的基本单元。</p><p><strong>触发器（Trigger）</strong> — 行为的 WHEN 部分，决定引擎什么时候来检查这条行为，比如&quot;每当变量变化时&quot;、&quot;每 N 回合&quot;、&quot;出现关键词时&quot;或&quot;计时器到时&quot;。</p><p><strong>递归触发（Recursion）</strong> — 词条 A 被触发后，其内容中的关键词会再次扫描并触发词条 B，形成连锁激活，深度由 <code>lorebookRecursionDepth</code> 控制（0-10 层）。</p><p><strong>动作（Action）</strong> — 行为的 DO 部分，条件满足后引擎实际执行的操作，包括修改变量、注入指令、通知玩家、播放音频、启动计时器等。</p><p><strong>二级关键词（Secondary Keywords）</strong> — 在主关键词命中后做进一步筛选的关键词列表，支持 AND_ANY、AND_ALL、NOT_ANY、NOT_ALL 四种组合逻辑。</p><p><strong>行为（Behavior）</strong> — WHEN/ONLY IF/DO 三段式的自动化逻辑：何时检查、满足什么条件、执行什么操作，是让世界&quot;活&quot;起来的核心机制。在编辑器的 Behaviors 区域配置。</p><p><strong>后历史（Post-History）</strong> — 提示词四大区域之一，放在所有聊天消息之后、AI 开始生成之前，适合放&quot;最后强调一遍&quot;的指令，因为 AI 对最后看到的内容印象最深。</p><p><strong>回合（Turn）</strong> — 一次完整的对话往返，即玩家发送一条消息加上 AI 生成一条回复算作一个回合。</p><p><strong>会话（Session）</strong> — 一次游戏对话的实例，每个会话独立维护自己的聊天历史和游戏状态，互不干扰。</p><p><strong>角色（Character）</strong> — 世界中由 AI 扮演的虚构人物，通过词条定义其外貌、性格、说话方式等设定。</p><p><strong>结构化输出（Structured Output）</strong> — 一项 AI 设置，开启后通过 <code>response_format: { type: &quot;json_object&quot; }</code> 强制 AI 以 JSON 格式回复，适合需要前端严格解析输出的场景。</p><p><strong>开场白（Greeting）</strong> — 玩家进入世界时看到的第一条 AI 消息，决定了整个体验的第一印象。</p><p><strong>冷却（Cooldown）</strong> — 行为触发后需要等待的回合数，防止同一条行为被过于频繁地反复触发。</p><p><strong>模糊匹配（Fuzzy Match）</strong> — 基于 Levenshtein 编辑距离的容错匹配，允许关键词有少量拼写错误仍能命中，仅对拉丁字母有效，不支持中日韩文字。</p><p><strong>全屏组件（Full Screen Component）</strong> — 一项设置，启用后自定义组件占据整个屏幕、聊天窗口完全隐藏，适合角色创建界面、地图或全屏游戏等沉浸式场景。</p><p><strong>渲染器（Renderer）</strong> — 用 TSX 代码完全接管消息或界面展示方式的机制，是让世界从&quot;聊天机器人&quot;升级为&quot;互动体验&quot;的关键。</p><p><strong>深度插入（Depth Injection）</strong> — 将词条内容插入聊天历史特定位置的技术，depth 值表示从末尾往回数第几条消息处插入，让 AI 更自然地&quot;注意到&quot;上下文信息。</p><p><strong>世界（World）</strong> — Yumina 中一个完整的互动体验，是把角色、故事、规则、组件、音频等所有要素打包在一起的顶层容器。</p><p><strong>世界书（Lorebook）</strong> — 由关键词触发的词条集合，当聊天中出现匹配关键词时对应词条自动注入 AI 上下文，实现按需投喂信息、节约 token 预算。</p><p><strong>条件（Condition）</strong> — 基于游戏变量当前值的判断表达式，由变量 ID、运算符（eq/neq/gt/gte/lt/lte/contains）和目标值三部分组成。</p><p><strong>条件BGM（Conditional BGM）</strong> — 根据变量状态、关键词或回合数等条件自动切换背景音乐的机制，比如进入战斗区域时自动换成战斗曲。</p><p><strong>图片面板（Image Panel）</strong> — 一种组件类型，用于展示角色立绘或场景图，可绑定变量让 AI 通过指令动态换图，也可以写死一个固定 URL。</p><p><strong>温度（Temperature）</strong> — 控制 AI 回复随机性的核心参数，范围 0-2；值越低输出越稳定可预测，值越高越有创造力但也越可能偏离主题。</p><p><strong>文字面板（Text Display）</strong> — 一种组件类型，用于显示格式化文本信息（如当前位置、天气），支持模板字符串和图标。</p><p><strong>物品（Item）</strong> — 背包格子组件中的单个元素，对应 JSON 数组变量里的一个条目，通过 push 添加、delete 移除。</p><p><strong>系统预设（System Preset）</strong> — 提示词四大区域之一，位于最顶部，AI 最先看到，适合放核心角色描述、世界观和写作风格等必须时刻生效的内容。</p><p><strong>消息渲染器（Message Renderer）</strong> — 用 TSX 编写的自定义组件，替换默认的 Markdown 聊天气泡，实现气泡对话、视觉小说、战斗日志等个性化消息外观。</p><p><strong>音效（SFX）</strong> — 一次性播放的短音频，如开门声、爆炸声、获得物品的提示音，可由 AI 音频指令或规则触发。</p><p><strong>音频指令（Audio Directive）</strong> — AI 在回复中通过 <code>[audio: trackId action]</code> 格式控制音频播放的特殊指令，支持 play、stop、crossfade、volume 和 chain 操作。</p><p><strong>优先级（Priority）</strong> — 行为或条件 BGM 上的数值权重，数字越大越先被评估和执行，当多条行为同时触发时决定谁先跑。</p><p><strong>指令（Directive）</strong> — AI 在回复中通过 <code>[变量名: 操作 值]</code> 格式改变游戏状态的方式，由引擎自动解析并执行，玩家只看到干净的叙事文本。</p><p><strong>状态条（Stat Bar）</strong> — 一种组件类型，绑定数字变量后以进度条形式展示数值，适合 HP、MP、经验值等需要直观呈现比例的场景。</p><p><strong>自定义组件（Custom Component）</strong> — 用 TSX 编写的独立 UI 面板，不替换消息渲染而是在聊天界面旁边额外添加，适合角色创建界面、游戏侧边栏等。</p><p><strong>组件（Component）</strong> — 游戏面板中绑定变量的可视化 UI 控件，变量值一变控件就自动更新，包括状态条、文字面板、图片面板、背包格子和 Web 面板五种内置类型。</p><p><strong>宏（Macro）</strong> — <code>{{名称}}</code> 格式的占位标记，在提示词构建时自动替换为对应变量的值或系统信息（如 <code>{{char}}</code>、<code>{{user}}</code>、<code>{{turnCount}}</code>）。</p><p><strong>Bundle</strong> — 将世界中的部分内容（词条、变量、规则、组件等）打包为可分享的 JSON 文件，别人可以一键安装到自己的世界中。</p><p><strong>语言变体（Language Variant）</strong> — 同一个世界的不同语言翻译版本。通过编辑器 Overview 里的语言设置可以把多个语言版本链接在一起，玩家开始游戏时会看到语言切换标签页。</p><p><strong>Web面板（Web Panel）</strong> — 一种组件类型，在 iframe 沙箱中运行自定义 HTML/CSS/JS，是最灵活的万能组件，可实现小地图、技能树等任意自定义 UI。</p></div>',1)])])}const _=t(e,[["render",p]]);export{l as __pageData,_ as default};
